    const row2 = el("div", { style: { display: "grid", gridTemplateColumns: "1fr 160px", gap: "10px", alignItems: "center", marginTop: "10px" } });
    const amountOut = el("input", { id: "amountOut", value: "0", type: "text", disabled: true, style: { padding: "10px", borderRadius: "10px", border: "1px solid #eee", background: "#fafafa" } });
    const tokenOutSel = el("select", { id: "tokenOut", style: { padding: "10px", borderRadius: "10px", border: "1px solid #ccc" } });

