        const q = await app.quoteV2({ amountIn: amountInParsed, path: [state.tokenIn, state.tokenOut] });
        state.quoteOut = q.amountOut;
        state.quoteOutText = SwapDApp.formatAmount(q.amountOut, state.decimalsOut);
        amountOut.value = state.quoteOutText;
