      if (s?.type === "swap") {
        if (s.step === "sign") setStatus("Swap: confirm in wallet…");
        if (s.step === "pending") setStatus(`Swap pending: ${s.hash}`);
        if (s.step === "confirmed") setStatus(`Swap confirmed: ${s.hash}`);
      }
      if (s?.type === "permit2") {
        if (s.step === "sign") setStatus("Permit2: confirm in wallet…");
        if (s.step === "pending") setStatus(`Permit2 pending: ${s.hash}`);
        if (s.step === "confirmed") setStatus(`Permit2 confirmed: ${s.hash}`);
      }
